import{c as a,Q as n,j as t,m as l}from"./chunks/framework.CBiVa4O3.js";const g=JSON.parse('{"title":"系统设计总览与心智","description":"","frontmatter":{},"headers":[],"relativePath":"../systemDesign/01-系统设计总览.md","filePath":"../systemDesign/01-系统设计总览.md","lastUpdated":1778496697000}'),e={name:"../systemDesign/01-系统设计总览.md"};function p(i,s,o,r,d,c){return n(),t("div",null,[...s[0]||(s[0]=[l(`<h1 id="系统设计总览与心智" tabindex="-1">系统设计总览与心智 <a class="header-anchor" href="#系统设计总览与心智" aria-label="Permalink to &quot;系统设计总览与心智&quot;">​</a></h1><p>学系统设计最大的障碍不是「方案不会」,是<strong>根本不知道该从哪儿开始想</strong>。面试官说「设计一个 Twitter」,新手第一反应是画一个 Spring Boot + MySQL + Redis 的图,然后开始填字段——这就<strong>错了 90%</strong>。系统设计不是「拼组件」,是<strong>先搞清楚问题大小,再决定要不要用重武器</strong>。这一篇不讲任何具体方案,只讲一件事:<strong>面对「设计 X」时,脑子里到底应该先转什么</strong>。</p><blockquote><p>一句话先记住:<strong>系统设计 = 把模糊需求翻译成&quot;流量数字 + 数据模型 + 失败假设&quot;三件套,再选最便宜的方案撑住</strong>。看上去答案是架构图,实际上 80% 的工作发生在画图之前——<strong>没估算清楚 QPS 的架构都是空中楼阁</strong>,你不知道每秒 100 请求和每秒 100 万请求是两个完全不同的世界。</p></blockquote><hr><h2 id="一、系统设计的本质-用约束反推方案" tabindex="-1">一、系统设计的本质:用约束反推方案 <a class="header-anchor" href="#一、系统设计的本质-用约束反推方案" aria-label="Permalink to &quot;一、系统设计的本质:用约束反推方案&quot;">​</a></h2><p>CRUD 应用没有「设计」一说——表建好、接口写好、上线。系统设计开始的边界点很清晰:<strong>当流量、数据、延迟、可用性中任何一个达到单机扛不住的量级</strong>,你就被迫离开 CRUD,进入设计。</p><p>设计的本质是<strong>在约束里找最便宜的可行解</strong>。约束有四类:</p><table tabindex="0"><thead><tr><th>约束</th><th>关键问题</th></tr></thead><tbody><tr><td>流量</td><td>每秒多少读 / 多少写?峰值是均值的几倍?</td></tr><tr><td>数据</td><td>存什么、存多大、留多久、怎么查?</td></tr><tr><td>延迟</td><td>用户能等多久?p99 多少?跨地域怎么算?</td></tr><tr><td>可用性</td><td>能不能挂?挂多久?挂了影响多少用户?</td></tr></tbody></table><blockquote><p>真正的工作流是:<strong>先问需求 → 推算约束 → 在约束下选方案</strong>,而不是反过来——「先用 Redis Cluster 再倒推为什么要用」就是新手最常见的错误。<strong>架构师的功夫,80% 在前两步</strong>,只有 20% 在画图。</p></blockquote><hr><h2 id="二、从模糊需求到清晰约束-四步法" tabindex="-1">二、从模糊需求到清晰约束:四步法 <a class="header-anchor" href="#二、从模糊需求到清晰约束-四步法" aria-label="Permalink to &quot;二、从模糊需求到清晰约束:四步法&quot;">​</a></h2><p>面试官扔来一句「设计一个微博」,你不应该直接动笔,应该按这四步问回去:</p><h3 id="_2-1-第一步-功能边界-做什么、不做什么" tabindex="-1">2.1 第一步:功能边界(做什么、不做什么) <a class="header-anchor" href="#_2-1-第一步-功能边界-做什么、不做什么" aria-label="Permalink to &quot;2.1 第一步:功能边界(做什么、不做什么)&quot;">​</a></h3><p>「设计微博」太大,先砍枝:</p><ul><li>用户发推、看 timeline、关注 / 取关——做</li><li>评论、点赞——做</li><li>私信、广告、推荐算法——<strong>这一轮不做</strong></li><li>视频、直播、电商——<strong>这一轮不做</strong></li></ul><blockquote><p>这一步不是偷懒,是<strong>把无限的问题变成有限的问题</strong>。面试 45 分钟讨论不完整个微博,不画边界你必输。真实工作里也一样,<strong>做减法是架构师最重要的能力</strong>。</p></blockquote><h3 id="_2-2-第二步-非功能需求-数字" tabindex="-1">2.2 第二步:非功能需求(数字) <a class="header-anchor" href="#_2-2-第二步-非功能需求-数字" aria-label="Permalink to &quot;2.2 第二步:非功能需求(数字)&quot;">​</a></h3><p>砍完功能,问数字:</p><ul><li>DAU(日活)是 1 万、100 万还是 1 亿?</li><li>写多还是读多?读写比 1:1 还是 1:1000?</li><li>数据要保留多久?</li><li>全球还是单地区?</li><li>容忍多少秒不可用?</li></ul><p><strong>这些数字直接决定架构等级</strong>。1 万 DAU 单机 + 一个 Redis 就够了;1 亿 DAU 必须分库分表 + 多机房 + CDN。</p><h3 id="_2-3-第三步-容量估算-下一篇专讲" tabindex="-1">2.3 第三步:容量估算(下一篇专讲) <a class="header-anchor" href="#_2-3-第三步-容量估算-下一篇专讲" aria-label="Permalink to &quot;2.3 第三步:容量估算(下一篇专讲)&quot;">​</a></h3><p>把数字翻成 QPS、存储、带宽。一个简化心算:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DAU × 人均请求数 / (24 × 3600) = 平均 QPS</span></span>
<span class="line"><span>平均 QPS × 5 = 峰值 QPS(常用倍数,具体业务调整)</span></span></code></pre></div><p>例:1 亿 DAU,人均 50 次请求 → 平均 5.8 万 QPS → 峰值 30 万 QPS。<strong>有这个数字,后面所有&quot;用什么 DB&quot;都有根据</strong>。</p><h3 id="_2-4-第四步-核心数据模型" tabindex="-1">2.4 第四步:核心数据模型 <a class="header-anchor" href="#_2-4-第四步-核心数据模型" aria-label="Permalink to &quot;2.4 第四步:核心数据模型&quot;">​</a></h3><p>不写表结构,只问三件事:</p><ol><li><strong>核心实体是什么?</strong>(微博:User / Tweet / Follow / Timeline)</li><li><strong>数据访问模式是什么?</strong>(主要是按 user_id 查 timeline,不是全表扫描)</li><li><strong>量级在哪?</strong>(Tweet 表一年 100 亿行,Follow 表一年 10 亿行)</li></ol><blockquote><p>数据模型的关键不是「字段叫什么」,是**「访问模式」+「量级」决定了后面要不要分库分表 / 用 KV / 加缓存**。同样一个 Tweet 表,1 万行你怎么写都行,100 亿行你写错一个索引就爆。</p></blockquote><hr><h2 id="三、设计要展示的是「演进」-不是「终极版」" tabindex="-1">三、设计要展示的是「演进」,不是「终极版」 <a class="header-anchor" href="#三、设计要展示的是「演进」-不是「终极版」" aria-label="Permalink to &quot;三、设计要展示的是「演进」,不是「终极版」&quot;">​</a></h2><p>新手最常见的另一个错误是<strong>直接画 Kafka + Cassandra + Spark 的全家桶</strong>。这个图不解决任何问题,因为你没说清楚「为什么需要这些」。</p><p><strong>正确的做法是从最简单开始,逐步暴露瓶颈,再升级</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>V1: 单机</span></span>
<span class="line"><span>    user 表、tweet 表、follow 表都在一台 MySQL</span></span>
<span class="line"><span>    扛得住:DAU &lt; 10 万</span></span>
<span class="line"><span></span></span>
<span class="line"><span>V2: 加缓存 + 读写分离</span></span>
<span class="line"><span>    热点 timeline 进 Redis,MySQL 一主多从</span></span>
<span class="line"><span>    扛得住:DAU 100 万</span></span>
<span class="line"><span></span></span>
<span class="line"><span>V3: 分库分表 + 异步 fanout</span></span>
<span class="line"><span>    Tweet 按 tweet_id 分,User 按 user_id 分</span></span>
<span class="line"><span>    发推后异步推到关注者收件箱(Push 模型)</span></span>
<span class="line"><span>    扛得住:DAU 1000 万</span></span>
<span class="line"><span></span></span>
<span class="line"><span>V4: 推拉结合 + 多机房</span></span>
<span class="line"><span>    大 V 用 Pull(实时拉),普通用户用 Push</span></span>
<span class="line"><span>    多机房读写,异地多活</span></span>
<span class="line"><span>    扛得住:DAU 1 亿+</span></span></code></pre></div><p><strong>每一步升级都要说清楚:V1 是什么瓶颈卡住的,V2 才合理出现</strong>。比如「V1 的 timeline 查询要 join 100 万条 follow,单机 MySQL 撑不住,所以 V2 加 Redis」。这种演进式答题,<strong>面试官立刻看出你懂工程</strong>——而不是背了一个图。</p><hr><h2 id="四、四个永远要回答的「关键取舍」" tabindex="-1">四、四个永远要回答的「关键取舍」 <a class="header-anchor" href="#四、四个永远要回答的「关键取舍」" aria-label="Permalink to &quot;四、四个永远要回答的「关键取舍」&quot;">​</a></h2><p>每个设计决策背后都有取舍,讲不出取舍的设计就是抄答案:</p><h3 id="_4-1-一致性-vs-可用性-cap" tabindex="-1">4.1 一致性 vs 可用性(CAP) <a class="header-anchor" href="#_4-1-一致性-vs-可用性-cap" aria-label="Permalink to &quot;4.1 一致性 vs 可用性(CAP)&quot;">​</a></h3><ul><li>强一致(转账、库存):宁可不可用,不能多扣钱 → 选 CP</li><li>最终一致(微博点赞、关注数):稍微不一致没事,要可用 → 选 AP</li></ul><h3 id="_4-2-读优化-vs-写优化" tabindex="-1">4.2 读优化 vs 写优化 <a class="header-anchor" href="#_4-2-读优化-vs-写优化" aria-label="Permalink to &quot;4.2 读优化 vs 写优化&quot;">​</a></h3><ul><li>读多写少(微博 timeline、新闻):写时多做事(预计算、推 fanout),读时拿现成的</li><li>写多读少(日志、监控):写时只追加,读时再算</li></ul><h3 id="_4-3-同步-vs-异步" tabindex="-1">4.3 同步 vs 异步 <a class="header-anchor" href="#_4-3-同步-vs-异步" aria-label="Permalink to &quot;4.3 同步 vs 异步&quot;">​</a></h3><ul><li>关键路径(下单、扣款):同步,失败立即返回错误</li><li>可补偿路径(发邮件、通知、统计):异步走 MQ,失败重试</li></ul><h3 id="_4-4-存储成本-vs-计算成本" tabindex="-1">4.4 存储成本 vs 计算成本 <a class="header-anchor" href="#_4-4-存储成本-vs-计算成本" aria-label="Permalink to &quot;4.4 存储成本 vs 计算成本&quot;">​</a></h3><ul><li>算一次存起来重复读(预计算 timeline)= 多花存储,省 CPU</li><li>每次请求实时算 = 省存储,多花 CPU</li></ul><blockquote><p><strong>任何一个方案上面都能套这四对</strong>。面试时把取舍讲明白,比方案本身重要——因为方案永远不止一个,但<strong>清晰的取舍说明你知道为什么选它</strong>。</p></blockquote><hr><h2 id="五、失败假设-「会挂」是设计前提-不是设计后想" tabindex="-1">五、失败假设:「会挂」是设计前提,不是设计后想 <a class="header-anchor" href="#五、失败假设-「会挂」是设计前提-不是设计后想" aria-label="Permalink to &quot;五、失败假设:「会挂」是设计前提,不是设计后想&quot;">​</a></h2><p>CRUD 思维默认「东西不会挂」,系统设计反过来:<strong>默认所有东西都会挂,只是早晚</strong>。设计时永远要问:</p><table tabindex="0"><thead><tr><th>组件</th><th>它挂了会怎样?对策?</th></tr></thead><tbody><tr><td>单台 Web 服务器</td><td>流量切到其他 → 多副本 + LB</td></tr><tr><td>MySQL 主库</td><td>写不了 → 自动切主、半同步复制</td></tr><tr><td>Redis</td><td>缓存击穿打爆 DB → 多级缓存 + 限流 + 熔断</td></tr><tr><td>MQ</td><td>消息堆积或丢 → 持久化 + 重试 + 死信队列</td></tr><tr><td>整个机房</td><td>全挂 → 多机房 + DNS 切换</td></tr><tr><td>网络分区</td><td>一半节点联不上 → 共识算法或可降级模式</td></tr></tbody></table><p><strong>没考虑过失败的设计,是危险的设计</strong>。真实事故的诱因 90% 都是「我们没想到这个会挂」。</p><hr><h2 id="六、系统设计的三种深度-三种岗位" tabindex="-1">六、系统设计的三种深度,三种岗位 <a class="header-anchor" href="#六、系统设计的三种深度-三种岗位" aria-label="Permalink to &quot;六、系统设计的三种深度,三种岗位&quot;">​</a></h2><p>不是所有「系统设计」都一个量级,粗分三层:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L1 「能跑」    单机 / 简单缓存 / 一两台服务器</span></span>
<span class="line"><span>              CRUD 工程师能做,DAU &lt; 10 万</span></span>
<span class="line"><span></span></span>
<span class="line"><span>L2 「扛得住」  分库分表 / 多级缓存 / MQ 异步 / 限流</span></span>
<span class="line"><span>              中级后端的核心战力,DAU &lt; 1000 万</span></span>
<span class="line"><span></span></span>
<span class="line"><span>L3 「永远在」  多机房 / 异地多活 / 容灾 / 全球分发</span></span>
<span class="line"><span>              架构师 / 高级,DAU 1 亿+,涉及组织协作</span></span></code></pre></div><blockquote><p><strong>大多数面试问到 L2,大多数公司也只需要 L2</strong>。L3 是大厂少数核心系统的事(微信、淘宝、Twitter、Stripe),你不在那种岗位的话,精通 L2 就足以拿到 P7 / Senior。本系列重点是 L2,L3 在第四层简要带过。</p></blockquote><hr><h2 id="七、画架构图的最少元素" tabindex="-1">七、画架构图的最少元素 <a class="header-anchor" href="#七、画架构图的最少元素" aria-label="Permalink to &quot;七、画架构图的最少元素&quot;">​</a></h2><p>无论多复杂的系统,架构图就这几个框:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────┐    ┌──────┐    ┌────────┐    ┌──────┐    ┌──────┐</span></span>
<span class="line"><span>│ Client  │ →  │ CDN  │ →  │  LB    │ →  │ App  │ →  │ DB   │</span></span>
<span class="line"><span>└─────────┘    └──────┘    └────────┘    └──────┘    └──────┘</span></span>
<span class="line"><span>                                            ↓             ↑</span></span>
<span class="line"><span>                                        ┌──────┐    ┌──────┐</span></span>
<span class="line"><span>                                        │ MQ   │ →  │Worker│</span></span>
<span class="line"><span>                                        └──────┘    └──────┘</span></span>
<span class="line"><span>                                            ↓</span></span>
<span class="line"><span>                                        ┌──────┐</span></span>
<span class="line"><span>                                        │Cache │</span></span>
<span class="line"><span>                                        └──────┘</span></span></code></pre></div><p><strong>一个合格的架构图必须标清楚</strong>:</p><ul><li>每个箭头是同步还是异步</li><li>每个组件的副本数 / 分片数</li><li>数据流方向(读路径 / 写路径分开画)</li><li>关键的 QPS / 延迟 / 容量数字</li></ul><blockquote><p>没有这些标注的架构图,<strong>和小学生画的没区别</strong>。架构图不是装饰,是「让别人 30 秒看懂你的设计取舍」的工具。</p></blockquote><hr><h2 id="八、本系列的学习地图" tabindex="-1">八、本系列的学习地图 <a class="header-anchor" href="#八、本系列的学习地图" aria-label="Permalink to &quot;八、本系列的学习地图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01      总览(这篇)</span></span>
<span class="line"><span>02-05   心智:估算 / 演进 / CAP / 高可用</span></span>
<span class="line"><span>        看完知道&quot;在想什么&quot;,不会再被问懵</span></span>
<span class="line"><span></span></span>
<span class="line"><span>06-13   抗压设施:LB / 缓存 / 分库 / MQ / 限流 / 一致性哈希</span></span>
<span class="line"><span>        这一段是面试和实战的&quot;硬通货&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>14-24   经典案例:短链 → IM → 秒杀 → 12306</span></span>
<span class="line"><span>        把上面的设施串起来设计真实系统</span></span>
<span class="line"><span>        每篇套同一个五段模板,可以模仿</span></span>
<span class="line"><span></span></span>
<span class="line"><span>25-30   进阶:多机房 / 容灾 / 灰度 / 设计文档</span></span>
<span class="line"><span>        大厂场景,按职业阶段决定看不看</span></span></code></pre></div><p><strong>优先级</strong>:01-13 强烈推荐每篇都看;14-24 选感兴趣的;25-30 按需。</p><hr><h2 id="九、踩坑提醒-总览版-后面每篇细讲" tabindex="-1">九、踩坑提醒(总览版,后面每篇细讲) <a class="header-anchor" href="#九、踩坑提醒-总览版-后面每篇细讲" aria-label="Permalink to &quot;九、踩坑提醒(总览版,后面每篇细讲)&quot;">​</a></h2><ol><li><strong>不问需求就开始画图</strong>——做减法和定数字才是关键,画图只是产物</li><li><strong>用名词堆代替推理</strong>——上来就 &quot;ZooKeeper + Kafka + Cassandra&quot;,讲不出为什么</li><li><strong>忽略容量估算</strong>——所有「需要 Redis 集群」「需要 MQ」的依据都来自数字,没数字纯靠感觉</li><li><strong>画终极架构而不是演进</strong>——好设计是层层递进推出来的,不是从天而降的</li><li><strong>不讨论失败模式</strong>——「这个组件挂了怎么办」必须每个都答得出</li><li><strong>强一致和最终一致混淆</strong>——转账和点赞是两个世界,搞错就出大事</li><li><strong>同步当异步用 / 反之</strong>——关键路径异步会丢数据,非关键路径同步会拖垮</li><li><strong>不画读写路径分离</strong>——读写通常完全不同,一张图画不清楚</li><li><strong>忽略「这个数据后期怎么扩」</strong>——MySQL 100 亿行不分库,后面是地狱</li><li><strong>以为「系统设计」是一次画对</strong>——不是,是<strong>持续演进 + 持续重构</strong></li></ol><hr><p>下一篇:<code>02-容量估算.md</code>,讲 QPS / 存储 / 带宽的快速心算法,常见数量级的「肌肉记忆」(1 亿 DAU = 多少 QPS?100 亿条记录占多少磁盘?),和为什么算错一个数量级会让整个架构错。</p>`,72)])])}const u=a(e,[["render",p]]);export{g as __pageData,u as default};
